    <script>
        // Sample data from the user
        let currentData = {{json_dumps(rows)}};

        // Initialize Mermaid with dark theme
        mermaid.initialize({ startOnLoad: false, theme: 'dark', maxTextSize: 100000, sequence: { showSequenceNumbers: true } });

        function generateSequenceDiagram(data, conversationLabel = "Default Conversation") {


            let mermaidCode = "sequenceDiagram\n";

            // Update title
            document.getElementById('diagram-title').textContent = `AI Interaction Diagram: ${conversationLabel}`;

            // Define participants based on the data
            const userId = data[0].USER_ID || "Client";
            let clientType = "Agents";
            if (userId.includes("@")) {
                clientType = "Users";
            };
            const userIdShort = userId.split('@')[0]; // Get the username part for cleaner display
            const llmName = data[0].llm || data.at(-1).llm || "LLM"; // Get LLM name from data

            mermaidCode += `    box rgb(80,80,200) ${clientType}\n`;
            mermaidCode += `    participant Client as ${userIdShort}\n`;
            mermaidCode += `    end\n`;
            mermaidCode += `    participant MCP_Client as MCP Client\n`;
            mermaidCode += `    box rgb(100,0,100) AI Models\n`;
            mermaidCode += `    participant ${llmName} as ${llmName}\n`;
            mermaidCode += `    end\n`;
            mermaidCode += `    participant MCP_Server as MCP Server\n`;

            mermaidCode += `    box rgb(30,81, 40) Toolsets\n`;

            // Get unique tool domains
            const toolDomains = [...new Set(data
                .filter(item => item.tool_domain)
                .map(item => item.tool_domain))];

            toolDomains.forEach(domain => {
                mermaidCode += `    participant ${domain} as ${domain}\n`;
            });

            mermaidCode += `    end\n`;

            mermaidCode += "\n";
            let rectToggle = false;

            // Process each data entry according to the rules
            data.forEach((item, index) => {
                if (item.type === "client") {
                    // Rule: Draw line from client to MCP Client and then from MCP Client to LLM
                    const persona = item.persona || "Unknown"
                    const shortMessage = item.message.length > 30 
                        ? item.message.substring(0, 30) + "..." 
                        : item.message;
                    mermaidCode += `    Client->>MCP_Client: [${persona}] ${shortMessage.replace(/\n/g, ' ')}\n`;
                    mermaidCode += `    MCP_Client->>+${llmName}: Forward request + System Instructions\n\n`;

                } else if (item.type === "openai" && item.tool_name) {
                    // Rule: Tool calling sequence
                    const toolName = item.tool_name;
                    const toolDomain = item.tool_domain;

                    mermaidCode += `    note left of ${llmName}: Tool Call ${toolName}\n`;
                    const rectColor = rectToggle ? 'rgba(120, 120, 120, 0.8)' : 'rgba(120, 120, 120, 0.8)';
                    mermaidCode += `    rect ${rectColor}\n`;

                    mermaidCode += `        ${llmName}->>MCP_Client: ${toolName}\n`;
                    mermaidCode += `        MCP_Client->>MCP_Server: ${toolName}\n`;
                    mermaidCode += `        MCP_Server->>${toolDomain}: ${toolName}\n`;
                    mermaidCode += `        ${toolDomain}->>MCP_Server: ${toolName} Response\n`;
                    mermaidCode += `        MCP_Server->>MCP_Client: ${toolName} Response\n`;
                    mermaidCode += `        MCP_Client->>${llmName}: ${toolName} Response\n`;
                    mermaidCode += `    end\n\n`;

                    rectToggle = !rectToggle;

                } else if (item.type === "openai" && !item.tool_name) {
                    // Rule: Response from LLM to MCP_Client and then to User with "Response" label
                    mermaidCode += `    ${llmName}->>-MCP_Client: Response\n`;
                    mermaidCode += `    MCP_Client->>Client: Response\n`;
                }
            });

            return mermaidCode;
        }

        function generateDiagram(conversationLabel = "Security PSIRT Analysis") {
            try {
                const mermaidCode = generateSequenceDiagram(currentData, conversationLabel);

                // Clear previous diagram
                const diagramDiv = document.getElementById('diagram');
                diagramDiv.innerHTML = '';

                // Render new diagram
                mermaid.render('sequence-diagram', mermaidCode)
                    .then(result => {
                        diagramDiv.innerHTML = result.svg;
                    })
                    .catch(error => {
                        console.error('Error rendering diagram:', error);
                        diagramDiv.innerHTML = '<p style="color: #ff6b6b;">Error rendering diagram. Check console for details.</p>';
                    });
            } catch (error) {
                console.error('Error generating diagram:', error);
                document.getElementById('diagram').innerHTML = '<p style="color: #ff6b6b;">Error processing data: ' + error.message + '</p>';
            }
        }



        // Function to use custom data programmatically
        function useCustomData(newData, conversationLabel = "Custom Conversation") {
            currentData = newData;
            generateDiagram(conversationLabel);
        }

        // Generate initial diagram
        window.onload = function() {
            generateDiagram(conversationLabel="{{conversationLabel}}");
        };
    </script>
</body>
</html>

